def gen(rng, size):
    sx = rng.randrange(0, 50)
    sy = rng.randrange(0, 50)
    x, y = sx, sy
    steps = rng.randrange(0, 6)
    for _ in range(steps):
        m = max(x, y)
        if m == 0:
            break
        if rng.random() < 0.5:
            x += m
        else:
            y += m
    # sometimes perturb to make it unreachable
    if rng.random() < 0.3:
        x += rng.randrange(1, 3)
    return [sx, sy, x, y]

