class Solution:
    def minMoves(self, sx, sy, tx, ty):
        import sys
        sys.setrecursionlimit(10000)
        from functools import lru_cache
        best = {}
        INF = float('inf')
        # DFS with memo on (x,y) -> min moves to target, pruning out-of-bounds
        memo = {}
        def dfs(x, y):
            if x == tx and y == ty:
                return 0
            if x > tx or y > ty:
                return INF
            m = max(x, y)
            if m == 0:
                return INF
            key = (x, y)
            if key in memo:
                return memo[key]
            memo[key] = INF  # guard against revisits in this acyclic-by-growth graph
            r = min(dfs(x + m, y), dfs(x, y + m))
            res = INF if r == INF else r + 1
            memo[key] = res
            return res
        ans = dfs(sx, sy)
        return -1 if ans == INF else ans

