class Solution:
    def minMoves(self, sx, sy, tx, ty):
        from collections import deque
        if sx == tx and sy == ty:
            return 0
        start = (sx, sy)
        dist = {start: 0}
        dq = deque([start])
        while dq:
            x, y = dq.popleft()
            d = dist[(x, y)]
            m = max(x, y)
            if m == 0:
                continue
            for nx, ny in ((x + m, y), (x, y + m)):
                if nx > tx or ny > ty:
                    continue
                if (nx, ny) in dist:
                    continue
                if nx == tx and ny == ty:
                    return d + 1
                dist[(nx, ny)] = d + 1
                dq.append((nx, ny))
        return -1

