var minMoves = function(sx, sy, tx, ty) {
    if (sx === tx && sy === ty) return 0;
    const key = (x, y) => x + ',' + y;
    const dist = new Map();
    dist.set(key(sx, sy), 0);
    const queue = [[sx, sy]];
    let qh = 0;
    while (qh < queue.length) {
        const [x, y] = queue[qh++];
        const d = dist.get(key(x, y));
        const m = Math.max(x, y);
        if (m === 0) continue;
        const nexts = [[x + m, y], [x, y + m]];
        for (const [nx, ny] of nexts) {
            if (nx > tx || ny > ty) continue;
            const k = key(nx, ny);
            if (dist.has(k)) continue;
            if (nx === tx && ny === ty) return d + 1;
            dist.set(k, d + 1);
            queue.push([nx, ny]);
        }
    }
    return -1;
};
